import { useMemo, useState } from "react";
import jsPDF from "jspdf";

function App() {
    const [resumeText, setResumeText] = useState("");
    const [jobDescription, setJobDescription] = useState("");
    const [analysis, setAnalysis] = useState(null);

    const [file, setFile] = useState(null);
    const [jdFile, setJdFile] = useState(null);

    const [uploadMessage, setUploadMessage] = useState("");
    const [jdUploadMessage, setJdUploadMessage] = useState("");

    const [loading, setLoading] = useState(false);
    const [darkMode, setDarkMode] = useState(false);

    const theme = useMemo(() => {
        return darkMode
            ? { bg: "#0f172a", card: "#111827", text: "#f9fafb" }
            : { bg: "#f8fafc", card: "#ffffff", text: "#111827" };
    }, [darkMode]);

    /* ---------------- RESUME UPLOAD ---------------- */
    const uploadResume = async () => {
        if (!file) {
            setUploadMessage("❌ Please select a resume PDF");
            return;
        }

        const formData = new FormData();
        formData.append("resume", file);

        setLoading(true);
        setUploadMessage("");

        try {
            const res = await fetch("http://localhost:5000/upload", {
                method: "POST",
                body: formData
            });

            const data = await res.json();

            if (!data.extractedText) {
                // ❌ WRONG FILE
                setUploadMessage(data.message);
                return;
            }

            // ✅ CORRECT FILE
            setResumeText(data.extractedText);
            setUploadMessage(data.message);

        } catch (error) {
            setUploadMessage("❌ Error uploading resume");
        } finally {
            setLoading(false);
        }
    };

    /* ---------------- JD UPLOAD ---------------- */
    const uploadJd = async () => {
        if (!jdFile) {
            setJdUploadMessage("❌ Please select a JD PDF");
            return;
        }

        const formData = new FormData();
        formData.append("jdFile", jdFile);

        setLoading(true);
        setJdUploadMessage("");

        try {
            const res = await fetch("http://localhost:5000/upload-jd", {
                method: "POST",
                body: formData
            });

            const data = await res.json();

            if (!data.extractedText) {
                // ❌ WRONG FILE
                setJdUploadMessage(data.message);
                return;
            }

            // ✅ CORRECT FILE
            setJobDescription(data.extractedText);
            setJdUploadMessage(data.message);

        } catch (error) {
            setJdUploadMessage("❌ Error uploading JD");
        } finally {
            setLoading(false);
        }
    };

    /* ---------------- ANALYZE ---------------- */
    const analyzeResume = async () => {
        if (!resumeText || !jobDescription) {
            alert("Upload Resume + JD first");
            return;
        }

        setLoading(true);

        const res = await fetch("http://localhost:5000/analyze", {
            method: "POST",
            headers: {
                "Content-Type": "application/json"
            },
            body: JSON.stringify({ resumeText, jobDescription })
        });

        const data = await res.json();

        setAnalysis(data);
        setLoading(false);
    };

    /* ---------------- PDF ---------------- */
    const downloadReport = () => {
        if (!analysis) return;

        const doc = new jsPDF();
        doc.text("AI Resume Analyzer Report", 10, 10);
        doc.text(`Score: ${analysis.score}`, 10, 20);

        doc.save("resume-analysis.pdf");
    };

    return (
        <div style={{ background: theme.bg, minHeight: "100vh", padding: 20 }}>
            <div style={{ maxWidth: 900, margin: "auto", background: theme.card, padding: 20, color: theme.text }}>

                <h1>AI Resume Analyzer 🚀</h1>

                <button onClick={() => setDarkMode(!darkMode)}>
                    Toggle Mode
                </button>

                {/* RESUME */}
                <h3>Upload Resume</h3>
                <input type="file" onChange={(e) => setFile(e.target.files[0])} />

                <button onClick={uploadResume}>
                    {loading ? "Uploading..." : "Upload Resume"}
                </button>

                <p style={{
                    color: uploadMessage.includes("❌") ? "red" : "green",
                    fontWeight: "bold"
                }}>
                    {uploadMessage}
                </p>

                {/* JD */}
                <h3>Upload Job Description</h3>
                <input type="file" onChange={(e) => setJdFile(e.target.files[0])} />

                <button onClick={uploadJd}>
                    {loading ? "Uploading..." : "Upload JD"}
                </button>

                <p style={{
                    color: jdUploadMessage.includes("❌") ? "red" : "green",
                    fontWeight: "bold"
                }}>
                    {jdUploadMessage}
                </p>

                {/* ANALYZE */}
                <button onClick={analyzeResume}>
                    Analyze Match
                </button>

                {/* RESULT */}
                {analysis && (
                    <div>
                        <h2>Score: {analysis.score}</h2>

                        <h3>Matched Skills</h3>
                        {analysis.matchedSkills.map((s, i) => (
                            <span key={i}> {s} </span>
                        ))}

                        <h3>Missing Skills</h3>
                        {analysis.missingSkills.map((s, i) => (
                            <span key={i}> {s} </span>
                        ))}

                        <button onClick={downloadReport}>
                            Download PDF
                        </button>
                    </div>
                )}
            </div>
        </div>
    );
}

export default App;
